-- ── Passbolt ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Passbolt is an open-source password manager built for teams, offering encrypted credential sharing, self-hosted or cloud deployment, and AGPL-licensed source code developed by a Luxembourg-based company.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community edition); Pro from EUR 4.50/user/month billed annually$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Belvaux, Luxembourg$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Passbolt Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Passbolt review 2026: open-source team password manager pricing, self-hosted vs cloud options, security features, pros and cons, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Passbolt is an open-source password manager designed specifically for teams and organizations, built on the OpenPGP standard and distributed under the AGPLv3 license. The project was started in 2014 by co-founders Kevin Muller and Cedric Alfonsi and the company was later established in Luxembourg, where Passbolt SA is headquartered in Belvaux; the business has received financial backing tied to the Grand Duchy of Luxembourg and closed an 8 million dollar Series A round in January 2025 to expand its password-collaboration and access-management capabilities. Passbolt's core differentiator versus mainstream consumer password managers like 1Password or Dashlane is its open-source, self-hostable architecture: organizations, particularly software development and DevOps teams, can run Passbolt on their own infrastructure for full control over encryption keys and data residency, or use Passbolt's own cloud-hosted version for convenience. The product centers on encrypted password storage and sharing, private and shared folders, user and group-based role access control, tagging, and an audit log of account activity, with browser extensions and desktop/mobile clients supporting the workflow. Pricing follows a freemium, self-hosted-first model: the Community edition is free forever with unlimited users and covers core password management, sharing, and two-factor secret-key authentication; the Pro edition costs EUR 4.50 per user per month billed annually (with a 10-user minimum and volume discounts above 100 users) and adds single sign-on via Microsoft, Google, or OpenID, LDAP and Active Directory provisioning, account recovery, and next-business-day support; an Enterprise edition adds custom development, high-availability and disaster-recovery consulting, and phone support under a 4-hour SLA. Special discounted terms are available for nonprofits, educational institutions, and open-source projects. Passbolt's target users are engineering-led organizations, agile and DevOps teams, and privacy- or compliance-conscious companies (including those in the EU seeking data sovereignty) that want a transparent, auditable alternative to closed-source enterprise password managers. Its main competitors include 1Password Business, Bitwarden (another open-source option), Dashlane Business, and Keeper Security, with Bitwarden being the closest comparison given its similarly open-source, self-hostable model.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8a88a88b-6d60-45fe-acbd-4156c50580ba';

