-- ── Payhawk ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Payhawk is a European spend management platform combining corporate cards, expense management, accounts payable, and procurement automation with AI-driven controls for mid-market and enterprise companies.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$599/month (Cards and Expenses or Bill Payments plan)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom (founded in Sofia, Bulgaria)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Payhawk Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Payhawk review 2026: spend management and corporate card platform pricing, features, pros and cons, and top alternatives for finance teams.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Payhawk is a spend management platform founded in 2018 in Sofia, Bulgaria by Hristo Borisov, Boyko Karadzhov, and Konstantin Dzhengozov, and is now registered and headquartered in London, United Kingdom, with additional offices across Europe and the United States. In March 2022 Payhawk raised a 100 million dollar Series B extension led by Lightspeed Venture Partners at a valuation of roughly 1 billion dollars, becoming the first Bulgarian company to reach unicorn status; total funding to date is roughly 239 million dollars from investors including Greenoaks, Sprints Capital, HubSpot Ventures, and QED Investors, and the company reported plans in early 2026 to raise further funding at a valuation near 2 billion dollars. Payhawk's platform combines corporate Visa cards issued across multiple currencies, expense management with automatic receipt capture, invoice and bill payment processing, and procurement (procure-to-pay) workflows, layered with AI-powered automation for approvals, policy enforcement, and reconciliation. Its key differentiator versus US-centric competitors like Ramp or Brex is its European-first design: multi-currency cards that avoid foreign exchange fees within eight supported currencies, compliance with European accounting and tax requirements, and a customer base spanning 32-plus countries, making it a common choice for mid-market and enterprise companies headquartered in or operating across Europe. Pricing is not fully published but is known to start at 599 dollars per month for the Cards and Expenses or Bill Payments plan and 899 dollars per month for the Procure to Pay plan, with Payhawk pricing based on the number of admin and accountant seats and selected features rather than transaction volume or employee count, meaning every paid plan includes unlimited employee cardholders and transactions. Payhawk's target users are finance teams at mid-market and enterprise companies, particularly those with multi-entity or multi-country European operations, seeking a single system for cards, expenses, invoices, and procurement in place of multiple point solutions. Named competitors include Ramp, Brex, Airbase, Spendesk, and PayEm.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '72083907-7b29-4e6e-80d3-6134cca542d6';

