-- ── Payload CMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Payload CMS is an open-source, TypeScript-native headless content management system and application framework that developers self-host or run on Payload Cloud, now owned by Figma.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted, open source); Payload Cloud plans from $35/month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Grand Rapids, Michigan, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Payload CMS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Payload CMS review 2026: open-source TypeScript headless CMS pricing, self-hosted vs cloud options, features, pros and cons, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Payload CMS is an open-source, TypeScript-native headless content management system and application framework founded in 2018 by James Mikrut, Elliot DeNolf, and Dan Ribbens, three full-stack developers frustrated with existing CMS options that deprioritized developer experience. The company is headquartered in Grand Rapids, Michigan, bootstrapped for several years before joining the Y Combinator accelerator in 2022 and raising 5.2 million dollars in seed funding from investors including Gradient Ventures and MongoDB Ventures; in 2025 Payload was acquired by design software company Figma, which now owns and continues to develop the product. Payload's key differentiator versus other headless CMS platforms like Contentful, Sanity, or Strapi is that it is code-first and fully open source: developers define content models, access control, and hooks directly in TypeScript, and the entire admin panel is generated automatically from that schema, with the codebase self-hostable on any Node.js-compatible infrastructure using a Postgres or MongoDB database. Beyond content management, Payload doubles as a general-purpose application framework, letting developers build authentication, e-commerce logic, and custom business workflows on the same backend rather than bolting a CMS onto a separate application. Pricing follows an open-source-first model: the self-hosted software is free forever, and organizations pay only for their own hosting infrastructure; for teams that prefer a managed option, Payload Cloud offers paid tiers, with a Standard plan around 35 dollars per month for smaller projects and a Pro plan around 199 dollars per month for higher-traffic, dedicated-cluster deployments, plus a custom-priced Enterprise Cloud tier starting near 10,000 dollars per year for annual commitments. Payload's target users are software development teams and technical product teams, particularly those building content-heavy websites, e-commerce storefronts, or internal tools who want full control of their stack and data without vendor lock-in. Named competitors include Contentful, Sanity, Strapi (another open-source, self-hostable option), and Directus.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '14aeb166-94c7-4343-ba72-b485b767c52b';

